def _adjust_palette_lightness(palette, lightness_factor):
    from . import ImagePalette

    mode = palette.mode
    mode_len = len(mode)
    data = palette.palette
    new_data = bytearray(len(data))
    for i in range(0, len(data), mode_len):
        for j, channel in enumerate(mode):
            value = data[i + j]
            if channel == "A":
                new_data[i + j] = value
            else:
                new_data[i + j] = min(255, max(0, round(value * lightness_factor)))
    return ImagePalette.ImagePalette(mode, bytes(new_data))


